DocumentationThemeAsset.Content:
:root{color-scheme:light;--bg:#fafaf9;--ink:#0a0a0a;--muted:#555;--soft:#666;--faint:#999;--line:rgba(0,0,0,.06);--card:#fff}
*{box-sizing:border-box}
html{scroll-behavior:smooth;-webkit-font-smoothing:antialiased}
body{margin:0;background:var(--bg);color:var(--ink);font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}
code,pre,.mono{font-family:"JetBrains Mono","Cascadia Mono",Consolas,monospace}
a{color:inherit;text-decoration:none}
.top{position:fixed;inset:0 0 auto 0;z-index:50;background:rgba(250,250,249,.9);backdrop-filter:blur(20px);border-bottom:1px solid var(--line)}
.top-inner,.shell,.footer-inner{max-width:1180px;margin:0 auto;padding:0 24px}
.top-inner{height:56px;display:flex;align-items:center;justify-content:space-between}
.brand{display:flex;align-items:center;gap:10px;font-size:13px;font-weight:650;letter-spacing:0}
.nav{display:flex;align-items:center;gap:28px;font-size:12.5px}
.home{background:#0a0a0a;color:white;border-radius:6px;padding:8px 14px;font-size:12px}
.main{padding-top:56px;min-height:100vh}
.hero{padding:72px 0 76px;border-bottom:1px solid rgba(0,0,0,.04)}
.eyebrow{display:block;margin-bottom:24px;color:var(--faint);font-size:10px;letter-spacing:.16em;text-transform:uppercase;font-weight:600}
h1{margin:0 0 20px;font-size:52px;line-height:.92;letter-spacing:0;font-weight:800}
.lead{max-width:560px;color:var(--muted);font-size:15px;line-height:1.7}
.body{display:flex;gap:32px;align-items:flex-start}
.rail{position:sticky;top:72px;width:220px;max-height:calc(100vh - 88px);overflow:auto;flex:0 0 auto;padding:24px 16px 0 0}
.rail-title{margin:0 0 16px;color:var(--faint);font-size:10px;letter-spacing:.14em;text-transform:uppercase;font-weight:600}
.rail a{display:block;padding:4px 0;color:var(--soft);font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.content{flex:1;min-width:0;padding:36px 0 44px}
.band{margin-bottom:48px;padding-bottom:40px;border-bottom:1px solid var(--line)}
.band h2{font-size:16px;font-weight:700;letter-spacing:0;margin:0 0 16px}
.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}
.card{background:var(--card);border:1px solid rgba(0,0,0,.05);border-radius:6px;padding:16px}
.card code{font-size:12px;color:var(--faint)}
.card p{margin:4px 0 0;color:var(--muted);font-size:13px}
.subject-group-label{margin:32px 0 16px;padding-top:28px;border-top:1px solid var(--line);color:var(--faint);font-size:10px;letter-spacing:.16em;text-transform:uppercase;font-weight:600}
.subject{border-bottom:1px solid rgba(0,0,0,.04)}
.subject-button{width:100%;display:flex;align-items:center;gap:12px;padding:16px 0;text-align:left;border:0;background:transparent;color:inherit;cursor:pointer}
.chev{width:14px;color:var(--faint);flex:0 0 auto}
.subject-name{font-size:14.5px;font-weight:650;letter-spacing:0}
.subject-summary{margin:-8px 0 16px 26px;color:var(--soft);font-size:13.5px;line-height:1.6}
.subject-body{margin-left:26px;padding-bottom:24px}
.item-list{border:1px solid var(--line);border-radius:6px;overflow:hidden}
.item{background:white;border-bottom:1px solid rgba(0,0,0,.04);padding:14px 16px}
.item:last-child{border-bottom:0}
.item code{font-size:13px;font-weight:600}
.item p{margin:6px 0 0;color:var(--soft);font-size:13px;line-height:1.5}
.item pre{margin:8px 0 0;color:var(--faint);font-size:12px;white-space:pre-wrap;word-break:break-word;background:transparent}
.nested{margin-top:12px}
.narrative{margin:8px 0 0;color:var(--soft);font-size:13px;line-height:1.55}
.facts{display:flex;flex-wrap:wrap;gap:6px;margin-top:8px}
.fact{border:1px solid rgba(0,0,0,.06);border-radius:999px;padding:3px 8px;color:#777;font-size:11px}
footer{background:#0a0a0a;margin-top:80px}
.footer-inner{height:96px;display:flex;align-items:center;color:#a8a29e;font-size:12.5px;font-weight:650}
@media(max-width:900px){.nav,.rail{display:none}.body{display:block}.hero{padding:56px 0}.grid{grid-template-columns:1fr}h1{font-size:42px}.content{padding-top:28px}}
